var CustomerCmd = func() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "customer [CUSTOMER_ID]",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if namespace == "" { return fmt.Errorf("namespace is required") }
			_, err := internal.App.BillingAutoAdvancer.AdvanceInvoice(cmd.Context(), billing.InvoiceID{Namespace: namespace, ID: args[0]})
			return err
		},
	}
	return cmd
